parameters.jsCode:
const m = $('Redis9').first().json.mensajes;
const txt = Array.isArray(m) ? m.join(' ') : (m ?? '');
// Quita emojis, simbolos, espacios y restos de formato; si no queda texto real, corta.
const limpio = String(txt).replace(/[\p{Extended_Pictographic}\u200d\uFE0F\u2600-\u27BF\s\[\]"']/gu, '').trim();
if (!limpio) return [];   // solo emoji / vacio -> no se procesa ni se responde
return $input.all();

const item = $input.first().json;
let message = "";
if (item.Content) message = item.Content;
else if (item.content) message = item.content;
else if (item.text) message = item.text;
return [{ json: { message } }];
